import{_ as o,p as t,q as i,a1 as e}from"./framework-822ca1a4.js";const a={},l=e(`<h1 id="bom-操作" tabindex="-1"><a class="header-anchor" href="#bom-操作" aria-hidden="true">#</a> BOM 操作</h1><p>BOM（Browser Object Model 浏览器对象模型），BOM 提供了了很多的对象，用于访问浏览器的功能。这些功能都是由浏览器厂商所提供的，没有一个统一的标准，每个浏览器的 BOM 操作可能有一定的差异。BOM 的很多操作权限都很高（例如关闭浏览器窗口），可能某一些浏览器提供商会禁止使用这些功能，因此我们在实际开发中应该尽量减少 BOM 操作。</p><h3 id="body-位置属性" tabindex="-1"><a class="header-anchor" href="#body-位置属性" aria-hidden="true">#</a> body 位置属性</h3><ol><li>client 系列</li></ol><ul><li><code>元素.clientWidth</code> 元素的可视宽（width + 左右 padding）</li><li><code>元素.clientHeight</code> 元素的可视高 （height + 上下 padding）</li><li><code>元素.clientTop</code> 上边框的高度（border-top-width）</li><li><code>元素.clientLeft</code> 左边框的高度（border-left-width）</li></ul><ol start="2"><li>offset 系列</li></ol><ul><li><code>元素.offsetWidth</code> (width+padding+border)</li><li><code>元素.offsetHeight</code> (height+padding+border)</li><li><code>元素.offsetTop</code> 元素顶部到定位父元素的距离(没有定位父元素，则到 body)</li><li><code>元素.offsetLeft</code> 元素左边到定位父元素的距离(没有定位父元素，则到 body)</li></ul><ol start="3"><li>scroll 系列</li></ol><ul><li><code>元素.scrollTop</code> 被卷去的高</li><li><code>元素.scrollLeft</code> 被卷去的宽</li><li><code>元素.scrollWidth</code> 元素实际内容宽</li><li><code>元素.scrollHeight</code> 元素实际内容高</li></ul><h3 id="window-对象" tabindex="-1"><a class="header-anchor" href="#window-对象" aria-hidden="true">#</a> window 对象</h3><p>所有的浏览器都支持 window 对象。在浏览器中，window 对象有着双重的角色，他既是 JavaScript 访问浏览器窗口的一个接口，又是 ECMAScript 规定的一个 GLobal 对象。</p><ol><li><p><code>window.alert(&quot;我是一个警告框&quot;);//弹出一个警告框</code><img src="https://upload-images.jianshu.io/upload_images/19038988-df89bdf2c12dc066.png?imageMogr2/auto-orient/strip|imageView2/2/w/1240" alt=""></p></li><li><p><code>window.confirm(&quot;是否重置&quot;);//返回一个Boolean值</code><img src="https://upload-images.jianshu.io/upload_images/19038988-7510952eda2e8861.png?imageMogr2/auto-orient/strip|imageView2/2/w/1240" alt=""></p></li><li><p><code>window.prompt(&quot;提示信息&quot;, 默认值);//以字符串返回用户输入的值</code><img src="https://upload-images.jianshu.io/upload_images/19038988-95b30e273a69fb22.png?imageMogr2/auto-orient/strip|imageView2/2/w/1240" alt=""></p></li><li><p><code>open()//打开一个窗口</code><img src="https://upload-images.jianshu.io/upload_images/19038988-4616428c2efb00bf.png?imageMogr2/auto-orient/strip|imageView2/2/w/1240" alt=""></p></li><li><p><code>close()//关闭窗口,如果没有参数默认关闭当前窗口</code></p></li></ol><h3 id="location-对象" tabindex="-1"><a class="header-anchor" href="#location-对象" aria-hidden="true">#</a> location 对象</h3><p>location 是最有用的 BOM 对象之一，它提供了当前窗口加载的文档有关的信息，还提供了一些导航功能。location 既是 window 对象的属性，也是 document 对象的属性。</p><ol><li><code>hash &quot;#contents&quot;</code> 返回 URL 中的 hash（#号后跟零或多个字符），如果 URL 中不包 含散列，则返回空字符串</li><li><code>host &quot;www.wrox.com:8080&quot;</code> 返回服务器名称和端口号（如果有）</li><li><code>hostname &quot;www.wrox.com&quot;</code> 返回不带端口号的服务器名称</li><li><code>href &quot;http:/www.wrox.com&quot;</code> 返回当前加载页面的完整 URL。而 location 对象的<code>toString()</code>方法也返回这个值</li><li><code>pathname &quot;/WileyCDA/&quot;</code> 返回 URL 中的目录和（或）文件名</li><li><code>port &quot;8080&quot;</code> 返回 URL 中指定的端口号。如果 URL 中不包含端口号，则这个属性返回空字符串</li><li><code>protocol &quot;http:&quot;</code> 返回页面使用的协议。通常是<code>http:</code>或<code>https:search &quot;?q=javascript&quot; </code>返回 URL 的查询字符串。这个字符串以问号开头</li><li><code>console.log(location.search);</code> // 返回 URL 的查询字符串。这个字符串以问号开头</li></ol><h3 id="history-对象" tabindex="-1"><a class="header-anchor" href="#history-对象" aria-hidden="true">#</a> history 对象</h3><p>history 对象保存了用户的上网记录</p><ol><li><code>history</code>: 历史记录 <code>console.log(window.history);</code></li><li><code>go()</code>: 跳转页面</li><li><code>back()</code>: 返回</li><li><code>forward()</code>: 前进</li></ol><h3 id="navigator-对象" tabindex="-1"><a class="header-anchor" href="#navigator-对象" aria-hidden="true">#</a> navigator 对象</h3><p>navigator 对象的属性用于检测网页的浏览器类型</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>&lt;script type=&quot;text/javascript&quot;&gt;
	console.log(window.navigator);;
	window.onload = function() {
		var txt = &quot;&lt;p&gt;浏览器代号: &quot; + navigator.appCodeName + &quot;&lt;/p&gt;&quot;;
		txt += &quot;&lt;p&gt;浏览器名称: &quot; + navigator.appName + &quot;&lt;/p&gt;&quot;;
		txt += &quot;&lt;p&gt;浏览器版本: &quot; + navigator.appVersion + &quot;&lt;/p&gt;&quot;;
		txt += &quot;&lt;p&gt;启用Cookies: &quot; + navigator.cookieEnabled + &quot;&lt;/p&gt;&quot;;
		txt += &quot;&lt;p&gt;硬件平台: &quot; + navigator.platform + &quot;&lt;/p&gt;&quot;;
		txt += &quot;&lt;p&gt;用户代理: &quot; + navigator.userAgent + &quot;&lt;/p&gt;&quot;;
		txt += &quot;&lt;p&gt;用户代理语言: &quot; + navigator.systemLanguage + &quot;&lt;/p&gt;&quot;;
		document.write(txt);
	}
&lt;/script&gt;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://upload-images.jianshu.io/upload_images/19038988-aa863999ffde767a.png?imageMogr2/auto-orient/strip|imageView2/2/w/1240" alt=""><img src="https://upload-images.jianshu.io/upload_images/19038988-3dfc6b250d188e17.png?imageMogr2/auto-orient/strip|imageView2/2/w/1240" alt=""></p>`,22),d=[l];function c(n,r){return t(),i("div",null,d)}const u=o(a,[["render",c],["__file","BOM.html.vue"]]);export{u as default};
